#include <map>
#include <string>
#include "esp_log.h"
#include "esp_partition.h"
#include "esp_spi_flash.h"

extern const char* TAG;

class Assets {
private:
    const esp_partition_t* partition_;
    const char* mmap_root_;
    spi_flash_mmap_handle_t mmap_handle_;
    std::map<std::string, struct AssetInfo> assets_; // Assume AssetInfo holds offset/size

public:
    Assets() : partition_(nullptr), mmap_root_(nullptr), mmap_handle_(0) {
        // Find the assets partition by label
        partition_ = esp_partition_find_first(ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_ANY, "assets");
        if (partition_ == nullptr) {
            ESP_LOGE(TAG, "Assets partition not found");
            return;
        }

        // Map the entire partition into memory
        esp_err_t err = esp_partition_mmap(partition_, 0, partition_->size, ESP_PARTITION_MMAP_DATA,
                                           (const void**)&mmap_root_, &mmap_handle_);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to mmap assets partition: %s", esp_err_to_name(err));
            return;
        }

        // Now parse the index or load asset directory from mapped memory
        void* index_ptr = nullptr;
        size_t index_size = 0;

        // Try to get index.json asset
        if (!GetAssetData("index.json", index_ptr, index_size)) {
            ESP_LOGE(TAG, "Could not retrieve index.json from assets");
            return;
        }

        // Parse index.json to populate assets_
        cJSON* root = cJSON_ParseWithLength((char*)index_ptr, index_size);
        if (root == nullptr) {
            ESP_LOGE(TAG, "Invalid index.json format");
            return;
        }

        // Example pseudo-code to extract asset info from JSON
        cJSON* item = nullptr;
        cJSON_ArrayForEach(item, root) {
            const char* name = item->string;
            cJSON* offset_json = cJSON_GetObjectItemCaseSensitive(item, "offset");
            cJSON* size_json = cJSON_GetObjectItemCaseSensitive(item, "size");

            if (name && offset_json && size_json &&
                cJSON_IsNumber(offset_json) && cJSON_IsNumber(size_json)) {
                AssetInfo info{};
                info.offset = offset_json->valueint;
                info.size = size_json->valueint;
                assets_[name] = info;
            }
        }

        cJSON_Delete(root);

        ESP_LOGI(TAG, "Assets initialized successfully");
    }

    ~Assets() {
        if (mmap_root_) {
            spi_flash_munmap(mmap_handle_);
        }
    }

    // Dummy placeholder for expected signature elsewhere
    bool GetAssetData(const std::string& name, void*& ptr, size_t& size);
};

