bool Assets::Apply()
{
    if (!checksum_valid_) {
        ESP_LOGE(TAG, "Cannot apply assets: checksum invalid");
        return false;
    }

    // Load custom fonts from assets
    void* font_data = nullptr;
    size_t font_size = 0;

    // Try to load custom text font
    if (GetAssetData("font.cbin", font_data, font_size)) {
        // Remove the "ZZ" magic header
        void* actual_font_data = static_cast<char*>(font_data) + 2;
        size_t actual_font_size = font_size - 2;

        // Create CBIN font
        auto custom_font = std::make_shared<LvglCBinFont>(actual_font_data);
        if (custom_font && custom_font->font()) {
            ESP_LOGI(TAG, "Custom font loaded successfully: line_height=%d", custom_font->font()->line_height);

            // Apply font to themes
            auto& theme_manager = LvglThemeManager::GetInstance();
            auto light_theme = theme_manager.GetTheme("light");
            auto dark_theme = theme_manager.GetTheme("dark");

            if (light_theme) {
                light_theme->set_text_font(custom_font);
            }
            if (dark_theme) {
                dark_theme->set_text_font(custom_font);
            }
        } else {
            ESP_LOGW(TAG, "Failed to create custom font from asset data");
        }
    } else {
        ESP_LOGD(TAG, "No custom font found in assets");
    }

    // Load other potential assets like emoji fonts, icons, etc.
    void* emoji_font_data = nullptr;
    size_t emoji_font_size = 0;

    if (GetAssetData("emoji.cbin", emoji_font_data, emoji_font_size)) {
