esp_err_t CheckVersion()
{
    auto &board = Board::GetInstance();
    auto network = board.GetNetwork();
    auto http = network->CreateHttp(0);

    if (!http) {
        ESP_LOGE(TAG, "Failed to create HTTP client");
        return ESP_FAIL;
    }

    // Set up headers similar to SetupHttp()
    auto user_agent = SystemInfo::GetUserAgent();
    http->SetHeader("Activation-Version", has_serial_number_ ? "2" : "1");
    http->SetHeader("Device-Id", SystemInfo::GetMacAddress().c_str());
    http->SetHeader("Client-Id", board.GetUuid());
    if (has_serial_number_) {
        http->SetHeader("Serial-Number", serial_number_.c_str());
    }
    http->SetHeader("User-Agent", user_agent.c_str());
    http->SetHeader("Accept-Language", Lang::CODE);
    http->SetHeader("Content-Type", "application/json");

    // Construct URL
    std::string url = GetCheckVersionUrl();
    if (url.empty()) {
        ESP_LOGE(TAG, "Invalid base URL for check version endpoint");
        return ESP_FAIL;
    }

    if (url.back() != '/') {
        url += "/check-version";
    } else {
        url += "check-version";
    }

    // Perform GET request
    if (!http->Open("GET", url)) {
        ESP_LOGE(TAG, "Failed to open HTTP connection to %s", url.c_str());
        return ESP_FAIL;
    }

    int status_code = http->GetStatusCode();
    if (status_code != 200) {
        ESP_LOGE(TAG, "Received unexpected HTTP status code: %d", status_code);
        return ESP_FAIL;
    }

    char *response_body = http->GetResponseBody();
    if (!response_body) {
        ESP_LOGE(TAG, "Empty response body received");
        return ESP_FAIL;
    }

    // Parse JSON response
    cJSON *root = cJSON_Parse(response_body);
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to parse JSON response");
        return ESP_FAIL;
    }

    cJSON *version_item = cJSON_GetObjectItem(root, "version");
    if (!cJSON_IsString(version_item)) {
        ESP_LOGE(TAG, "Missing or invalid 'version' field in response");
        cJSON_Delete(root);
        return ESP_FAIL;
    }

    cJSON *url_item = cJSON_GetObjectItem(root, "firmware_url");
    if (!cJSON_IsString(url_item)) {
        ESP_LOGE(TAG, "Missing or invalid 'firmware_url' field in response");
        cJSON_Delete(root);
        return ESP_FAIL;
    }

    std::string remote_version = version_item->valuestring;
    std::string firmware_url = url_item->valuestring;

    cJSON_Delete(root);

    // Compare versions
    if (IsNewVersionAvailable(firmware_version_, remote_version)) {
        ESP_LOGI(TAG, "New firmware version detected: %s", remote_version.c_str());
        firmware_version_ = remote_version;
        firmware_url_ = firmware_url;
        return ESP_OK;
    } else {
        ESP_LOGI(TAG, "Current firmware is up-to-date.");
        return ESP_OK;
    }
}

