// OTA Upgrade Function
bool Ota::Upgrade(const std::string &firmware_url, std::function<void(int progress, size_t speed)> callback)
{
    // Step 1: Get currently running partition
    const esp_partition_t* current_partition = esp_ota_get_running_partition();
    if (!current_partition)
    {
        ESP_LOGE(TAG, "Failed to get running partition");
        return false;
    }

    if (strcmp(current_partition->label, "factory") == 0)
    {
        ESP_LOGI(TAG, "Running from factory partition, skipping OTA");
        return false;
    }

    ESP_LOGI(TAG, "Current partition: %s", current_partition->label);

    esp_ota_img_states_t state;
    if (esp_ota_get_state_partition(current_partition, &state) != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to get partition state");
        return false;
    }

    if (state == ESP_OTA_IMG_PENDING_VERIFY)
    {
        ESP_LOGI(TAG, "Marking firmware as valid");
        esp_ota_mark_app_valid_cancel_rollback();
    }

    // Step 2: Compare versions (assuming global variables hold current version)
    extern std::string current_firmware_version; // Should be defined elsewhere
    std::string new_version = "2.1.0";           // Example placeholder – replace with dynamic value

    if (!IsNewerVersion(current_firmware_version, new_version))
    {
        ESP_LOGI(TAG, "No newer firmware found.");
        return false;
    }

    // Step 3: Find next update partition
    const esp_partition_t* update_partition = esp_ota_get_next_update_partition(NULL);
    if (!update_partition)
    {
        ESP_LOGE(TAG, "Failed to find next update partition");
        return false;
    }

    ESP_LOGI(TAG, "Writing to partition: %s", update_partition->label);

    // Step 4: Start OTA process
    esp_ota_handle_t ota_handle;
    esp_err_t err = esp_ota_begin(update_partition, OTA_SIZE_UNKNOWN, &ota_handle);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "esp_ota_begin failed (%s)", esp_err_to_name(err));
        return false;
    }

    // Step 5: Setup HTTP client
    esp_http_client_config_t config = {};
    config.url = firmware_url.c_str();
    config.timeout_ms = 30000;

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (!client)
    {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        esp_ota_abort(ota_handle);
        return false;
    }

    // Add required headers
    esp_http_client_set_header(client, "User-Agent", "ESP32-OTA-Updater");
    esp_http_client_set_header(client, "Device-Id", SystemInfo::GetMacAddress().c_str());

    // Open connection
    err = esp_http_client_open(client, 0);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to open HTTP connection: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        esp_ota_abort(ota_handle);
        return false;
    }

    int content_length = esp_http_client_fetch_headers(client);
    if (content_length <= 0)
    {
        ESP_LOGE(TAG, "Invalid content length");
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        esp_ota_abort(ota_handle);
        return false;
    }

    // Step 6: Read and write firmware data
    uint8_t buffer[1024];
    int total_read = 0;
    int last_progress = -1;
    TickType_t last_time = xTaskGetTickCount();

    while (total_read < content_length)
    {
        int read_len = esp_http_client_read(client, reinterpret_cast<char*>(buffer), sizeof(buffer));
        if (read_len < 0)
        {
            ESP_LOGE(TAG, "Error reading HTTP stream");
            break;
        }
        if (read_len == 0)
        {
            break; // Done
        }

        err = esp_ota_write(ota_handle, buffer, read_len);
        if (err != ESP_OK)
        {
            ESP_LOGE(TAG, "esp_ota_write failed (%s)", esp_err_to_name(err));
            break;
        }

        total_read += read_len;

        // Report progress every ~5%
        int progress = (total_read * 100) / content_length;
        if (progress != last_progress && (progress % 5 == 0 || progress >= 100))
        {
            TickType_t now = xTaskGetTickCount();
            size_t elapsed_ms = (now - last_time) * portTICK_PERIOD_MS;
            size_t bytes_per_sec = elapsed_ms > 0 ? ((total_read - (last_progress * content_length / 100)) * 1000) / elapsed_ms : 0;

            if (callback)
                callback(progress, bytes_per_sec);

            last_progress = progress;
            last_time = now;
        }
    }

    esp_http_client_close(client);
    esp_http_client_cleanup(client);

    if (total_read != content_length)
    {
        ESP_LOGE(TAG, "Incomplete download");
        esp_ota_abort(ota_handle);
        return false;
    }

    // Step 7: Finish OTA
    err = esp_ota_end(ota_handle);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "esp_ota_end failed (%s)", esp_err_to_name(err));
        return false;
    }

    // Step 8: Set boot partition
    err = esp_ota_set_boot_partition(update_partition);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "esp_ota_set_boot_partition failed (%s)", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "OTA update completed successfully. Rebooting...");
    esp_restart();

    return true;
}

