void WifiBoard::StartWifiConfigMode()
{
    // Check if already in config mode to prevent redundant operations
    if (WifiManager::GetInstance().IsConfigMode()) {
        ESP_LOGW(TAG, "Already in WiFi config mode");
        return;
    }

    ESP_LOGI(TAG, "Entering WiFi config mode");

    // Show notification to user about entering config mode
    GetDisplay()->ShowNotification(Lang::Strings::ENTERING_WIFI_CONFIG_MODE);

    // Reset application protocol to gracefully stop ongoing tasks
    auto &app = Application::GetInstance();
    auto state = app.GetDeviceState();

    if (state == kDeviceStateSpeaking || state == kDeviceStateListening || state == kDeviceStateIdle)
    {
        app.ResetProtocol();
    }

    // Create a temporary task to handle the delayed transition
    xTaskCreate([](void *arg)
                {
                    auto* board = static_cast<WifiBoard*>(arg);

                    // Allow some time for graceful shutdown of ongoing tasks
                    vTaskDelay(pdMS_TO_TICKS(1000));

                    // Stop any active station mode before entering config mode
                    WifiManager::GetInstance().StopStation();

                    // Stop the connect timer to prevent reconnection attempts
                    esp_timer_stop(board->connect_timer_);

                    // Actually start the WiFi configuration mode
                    WifiManager::GetInstance().StartConfigMode();

                    // Forward event to network layer
                    board->OnNetworkEvent(NetworkEvent::WifiConfigModeEnter);

                    ESP_LOGI(TAG, "WiFi config mode entered");

                    // Delete this temporary task as its job is done
                    vTaskDelete(NULL);
                }, "wifi_cfg_enter", 4096, this, 2, NULL);
}

