void LcdDisplay::SetTheme(Theme* theme) {
    DisplayLockGuard lock(this);

    // Cast to LvglTheme to access LVGL-specific attributes
    auto lvgl_theme = static_cast<LvglTheme*>(theme);
    if (!lvgl_theme) return;

    // Get current active screen
    lv_obj_t* screen = lv_screen_active();

    // Apply base theme styles globally
    lv_obj_set_style_bg_color(screen, lvgl_theme->background_color(), 0);
    lv_obj_set_style_text_color(screen, lvgl_theme->text_color(), 0);
    lv_obj_set_style_text_font(screen, lvgl_theme->text_font(), 0);

    // Update main static widgets
    if (label_) {
        lv_obj_set_style_text_color(label_, lvgl_theme->text_color(), 0);
        lv_obj_set_style_text_font(label_, lvgl_theme->text_font(), 0);
    }

    if (container_) {
        lv_obj_set_style_bg_color(container_, lvgl_theme->background_color(), 0);
        lv_obj_set_style_border_color(container_, lvgl_theme->border_color(), 0);
    }

    // Handle conditional UI layouts
#if CONFIG_USE_WECHAT_MESSAGE_STYLE
    // Traverse chat container children to update message bubble styles
    if (parent_object_) {
        uint32_t child_count = lv_obj_get_child_cnt(parent_object_);
        for (uint32_t i = 0; i < child_count; ++i) {
            lv_obj_t* obj = lv_obj_get_child(parent_object_, i);
            if (obj != nullptr) {
                // Assume each child is a message bubble container
                lv_obj_set_style_bg_color(obj, lvgl_theme->message_bubble_color(), 0);
                lv_obj_set_style_text_color(obj, lvgl_theme->message_text_color(), 0);
