    memcpy((uint8_t*)encrypted_data.data(), aes_nonce_.data(), aes_nonce_.size());

    // Perform CTR encryption of payload into buffer after nonce
    uint8_t stream_block[16] = {0};
    size_t nc_off = 0;

    int ret = mbedtls_aes_crypt_ctr(
        &aes_ctx_,
        packet->payload.size(),
        &nc_off,
        (uint8_t*)encrypted_data.data(),         // Initial counter block (nonce)
        stream_block,                            // Stream block output
        (const uint8_t*)packet->payload.data(),  // Input plaintext
        (uint8_t*)encrypted_data.data() + aes_nonce_.size()  // Output ciphertext
