    if (ret != 0) {
        ESP_LOGE(TAG, "Failed to encrypt audio data, ret: %d", ret);
        return false;
    }

    // Define and populate UDP header
    struct __attribute__((packed)) UdpHeader {
        uint8_t type = 0x01;
        uint8_t flags = 0x00;
        uint16_t payload_len;
        uint32_t ssrc;
        uint32_t timestamp;
        uint32_t sequence;
