    header.ssrc = htonl(0x12345678); // Static or dynamic SSRC
    header.timestamp = htonl(packet->timestamp);
    header.sequence = htonl(local_sequence_);

    // Assemble final packet: [header][nonce][encrypted_payload]
    std::string full_packet;
    full_packet.resize(sizeof(UdpHeader) + encrypted_size);
    memcpy(full_packet.data(), &header, sizeof(UdpHeader));
