```cpp
bool WebsocketProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (websocket_ == nullptr || !websocket_->IsConnected()) {
        ESP_LOGE(TAG, "WebSocket not connected. Cannot send audio.");
        return false;
    }

    // Construct binary header
    struct AudioFrameHeader {
        uint16_t version;
        uint16_t type;
        uint32_t timestamp;
        uint32_t payload_size;
    } __attribute__((packed));

    constexpr uint16_t PROTOCOL_VERSION = 2;
    constexpr uint16_t AUDIO_TYPE_PCM = 1;

    AudioFrameHeader header;
    header.version = htons(PROTOCOL_VERSION);
    header.type = htons(AUDIO_TYPE_PCM);
    header.timestamp = htonl(packet->timestamp);
    header.payload_size = htonl(static_cast<uint32_t>(packet->payload.size()));

    // Prepare full message buffer: header + payload
    std::vector<uint8_t> message_buffer(sizeof(header) + packet->payload.size());
    memcpy(message_buffer.data(), &header, sizeof(header));
    memcpy(message_buffer.data() + sizeof(header), packet->payload.data(), packet->payload.size());

    // Encrypt message using CTR mode
    std::string nonce(aes_nonce_);
    *(uint16_t*)&nonce[2] = htons(static_cast<uint16_t>(message_buffer.size()));
    *(uint32_t*)&nonce[8] = htonl(packet->timestamp);
    *(uint32_t*)&nonce[12] = htonl(++local_sequence_);

    std::vector<uint8_t> encrypted_message;
    encrypted_message.resize(nonce.size() + message_buffer.size());
    memcpy(encrypted_message.data(), nonce.data(), nonce.size());

    size_t nc_off = 0;
    uint8_t stream_block[16] = {0};

    int ret = mbedtls_aes_crypt_ctr(
        &aes_ctx_,
        message_buffer.size(),
        &nc_off,
        reinterpret_cast<const unsigned char*>(nonce.c_str()),
        stream_block,
        message_buffer.data(),
        encrypted_message.data() + nonce.size()
    );

    if (ret != 0) {
        ESP_LOGE(TAG, "Failed to encrypt audio data: %d", ret);
        return false;
    }

    // Send via WebSocket
    if (!websocket_->Send(reinterpret_cast<const char*>(encrypted_message.data()), encrypted_message.size(), true)) {
        ESP_LOGE(TAG, "Failed to send audio packet over WebSocket");
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    return true;
}

