        esp_err_t err = websocket_->Connect();
        if (err != ESP_OK)
        {
            ESP_LOGE(TAG, "Failed to connect WebSocket: %s", esp_err_to_name(err));
            return err;
        }
    }

    // Reset any previous errors or timeouts
    error_occurred_ = false;

    // Step 2: Send Hello Message
    std::string hello_msg = GetHelloMessage();
    if (hello_msg.empty())
    {
        ESP_LOGE(TAG, "Failed to generate hello message");
        return ESP_FAIL;
    }

    esp_err_t send_result = websocket_->Send(hello_msg.c_str(), hello_msg.length(), portMAX_DELAY);
    if (send_result != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to send hello message: %s", esp_err_to_name(send_result));
        error_occurred_ = true;
        return send_result;
    }

    // Step 3: Wait for Server's Hello Response
    EventBits_t bits = xEventGroupWaitBits(
        event_group_handle_,
        WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT,
        pdTRUE,   // Clear bit on exit
        pdFALSE,  // Wait for any bit
