        error_occurred_ = true;
        return ESP_ERR_TIMEOUT;
    }

    // At this point, ParseServerHello has been called by the receive handler
    // and session info should be populated.

    ESP_LOGI(TAG, "Audio channel opened successfully.");
    return ESP_OK;
}

