        if (cJSON_IsNumber(sample_rate_obj)) {
            sample_rate_ = sample_rate_obj->valueint;
            ESP_LOGI(TAG, "Sample rate: %d Hz", sample_rate_);
        }

        if (cJSON_IsNumber(channels_obj)) {
            channels_ = channels_obj->valueint;
            ESP_LOGI(TAG, "Channels: %d", channels_);
        }

        if (cJSON_IsNumber(frame_duration_obj)) {
            frame_duration_ms_ = frame_duration_obj->valueint;
            ESP_LOGI(TAG, "Frame duration: %d ms", frame_duration_ms_);
        }
    } else {
        ESP_LOGW(TAG, "Missing or invalid 'audio_params'");
    }

    // Parse features (optional)
    auto features_obj = cJSON_GetObjectItem(root, "features");
    if (cJSON_IsObject(features_obj)) {
        auto aec_obj = cJSON_GetObjectItem(features_obj, "aec");
        if (cJSON_IsBool(aec_obj)) {
            use_server_aec_ = cJSON_IsTrue(aec_obj);
            ESP_LOGI(TAG, "Server AEC: %s", use_server_aec_ ? "enabled" : "disabled");
        }

        auto mcp_obj = cJSON_GetObjectItem(features_obj, "mcp");
        if (cJSON_IsBool(mcp_obj)) {
            use_mcp_ = cJSON_IsTrue(mcp_obj);
            ESP_LOGI(TAG, "MCP support: %s", use_mcp_ ? "enabled" : "disabled");
        }
    }

    // Signal that we've processed the server hello
    xEventGroupSetBits(event_group_handle_, WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT);
}
